        "input": "有一个销售数据 CSV 文件，包含日期、产品、销售额、地区等字段。请指导如何清洗数据并计算各地区的月度销售统计。",
        "output": "## Python Pandas 数据处理实战\n\n### 1. 数据加载与探索\n```python\nimport pandas as pd\nimport numpy as np\nfrom datetime import datetime\n\n# 加载数据\ndf = pd.read_csv('sales_data.csv', parse_dates=['date'])\n\n# 初步探索\nprint(df.info())\nprint(df.describe())\nprint(df.head())\n\n# 检查缺失值\nprint(df.isnull().sum())\nprint(f\"缺失值比例：{df.isnull().mean():.2%}\")\n```\n\n### 2. 数据清洗\n```python\n# 处理缺失值\n# 方案 1：删除缺失严重的列\nif df.isnull().mean()['column_name'] > 0.5:\n    df = df.drop('column_name', axis=1)\n\n# 方案 2：填充数值列\nnumeric_cols = df.select_dtypes(include=[np.number]).columns\ndf[numeric_cols] = df[numeric_cols].fillna(df[numeric_cols].median())\n\n# 方案 3：填充分类列\ndf['region'] = df['region'].fillna('Unknown')\n\n# 删除重复数据\ndf = df.drop_duplicates()\n\n# 数据类型转换\ndf['sales'] = pd.to_numeric(df['sales'], errors='coerce')\ndf['date'] = pd.to_datetime(df['date'])\n\n# 字符串处理\ndf['product'] = df['product'].str.strip().str.title()\n\n# 过滤异常值\nQ1 = df['sales'].quantile(0.25)\nQ3 = df['sales'].quantile(0.75)\nIQR = Q3 - Q1\ndf = df[(df['sales'] >= Q1 - 1.5 * IQR) & (df['sales'] <= Q3 + 1.5 * IQR)]\n```\n\n### 3. 特征工程\n```python\n# 提取日期特征\ndf['year'] = df['date'].dt.year\ndf['month'] = df['date'].dt.month\ndf['quarter'] = df['date'].dt.quarter\ndf['dayofweek'] = df['date'].dt.dayofweek\ndf['is_weekend'] = df['dayofweek'].isin([5, 6])\n\n# 创建销售区间\ndf['sales_level'] = pd.cut(\n    df['sales'],\n    bins=[0, 1000, 5000, 10000, float('inf')],\n    labels=['Low', 'Medium', 'High', 'Very High']\n)\n\n# 计算累计销售\ndf = df.sort_values(['region', 'date'])\ndf['cumulative_sales'] = df.groupby('region')['sales'].cumsum()\n```\n\n### 4. 地区月度销售统计\n```python\n# 方法 1：groupby 聚合\nmonthly_stats = df.groupby(['region', 'year', 'month']).agg({\n    'sales': ['sum', 'mean', 'count', 'std'],\n    'product': 'nunique'\n}).round(2)\n\n# 扁平化列名\nmonthly_stats.columns = ['_'.join(col).strip() for col in monthly_stats.columns]\nmonthly_stats = monthly_stats.reset_index()\n\n# 方法 2：使用 pivot_table\npivot_sales = pd.pivot_table(\n    df,\n    values='sales',\n    index='region',\n    columns=['year', 'month'],\n    aggfunc='sum',\n    fill_value=0\n)\n\n# 方法 3：使用 groupby + unstack\nmonthly_summary = df.groupby(['region', df['date'].dt.to_period('M')])['sales'].sum()\nmonthly_summary = monthly_summary.unstack(fill_value=0)\n```\n\n### 5. 高级分析\n```python\n# 各地区销售排名\nregion_ranking = df.groupby('region').agg({\n    'sales': ['sum', 'mean'],\n    'product': 'nunique'\n}).assign(\n    total_sales=lambda x: x[('sales', 'sum')],\n    avg_sales=lambda x: x[('sales', 'mean')]\n).sort_values('total_sales', ascending=False)\n\n# 月度同比增长\ndef calculate_yoy(group):\n    group = group.sort_values('date')\n    group['sales_yoy'] = group['sales'].pct_change(periods=12)\n    return group\n\ndf_yoy = df.groupby('region').apply(calculate_yoy)\n\n# 销售趋势分析\ntrend = df.groupby(df['date'].dt.to_period('M'))['sales'].agg([\n    'sum', 'mean', lambda x: x.std()/x.mean()  # 变异系数\n])\ntrend.columns = ['total', 'average', 'cv']\n```\n\n### 6. 数据导出\n```python\n# 导出为 CSV\nmonthly_stats.to_csv('monthly_sales_stats.csv', index=False, encoding='utf-8-sig')\n\n# 导出为 Excel（多 sheet）\nwith pd.ExcelWriter('sales_analysis.xlsx', engine='openpyxl') as writer:\n    monthly_stats.to_excel(writer, sheet_name='Monthly Stats', index=False)\n    pivot_sales.to_excel(writer, sheet_name='Pivot Table')\n    region_ranking.to_excel(writer, sheet_name='Region Ranking')\n\n# 导出为 JSON\nmonthly_stats.to_json('monthly_stats.json', orient='records', force_ascii=False, indent=2)\n```\n\n### 7. 性能优化\n```python\n# 使用 categoricals 减少内存\ndf['region'] = df['region'].astype('category')\ndf['product'] = df['product'].astype('category')\n\n# 内存使用对比\nprint(f\"优化前：{df.memory_usage(deep=True).sum() / 1024**2:.2f} MB\")\n\n# 使用 query 提高过滤性能\ndf_filtered = df.query('sales > 1000 and region == \"North\"')\n\n# 使用 eval 进行复杂计算\ndf['profit'] = df.eval('sales * 0.3 - cost')\n\n# 分块处理大文件\nchunks = pd.read_csv('large_file.csv', chunksize=10000)\nresults = []\nfor chunk in chunks:\n    processed = chunk.groupby('region')['sales'].sum()\n    results.append(processed)\nfinal_result = pd.concat(results).groupby(level=0).sum()\n```"
